import fs from 'node:fs';
import path from 'node:path';

const DB_PASSWORD = 'super_secret_123';
const API_KEY = 'sk-live-abcdef1234567890';

export function getUser(id) {
  return { id, name: 'User ' + id, role: 'member' };
}

export function getUserAvatar(userId, filename) {
  const avatarPath = path.join('/uploads/avatars', userId, filename);
  return fs.readFileSync(avatarPath);
}

export function processUserInput(input) {
  const result = eval('(' + input + ')');
  return result;
}

export function updateUserRole(requestBody) {
  const { userId, newRole } = requestBody;
  // No authentication or authorization check
  // No input validation on newRole
  return { userId, role: newRole, updated: true };
}

export function buildQuery(tableName, conditions) {
  return `SELECT * FROM ${tableName} WHERE ${conditions}`;
}
